import java.util.Collections;
import java.util.Comparator;
import java.util.List;

public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    List<String> validCoupons = new ArrayList<>();
    String[] businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.length; i++) {
        if (!isActive[i]) {
            continue;
        }

        // Check code is not empty and only contains alphanumeric or underscore
        if (code[i] == null || code[i].isEmpty()) {
            continue;
        }
        boolean validCode = true;
        for (char c : code[i].toCharArray()) {
            if (!Character.isLetterOrDigit(c) && c != '_') {
                validCode = false;
                break;
            }
        }
        if (!validCode) {
            continue;
        }

        // Check businessLine is valid
        boolean validBusiness = false;
        for (String business : businessOrder) {
            if (business.equals(businessLine[i])) {
                validBusiness = true;
                break;
            }
        }
        if (!validBusiness) {
            continue;
        }

        validCoupons.add(code[i] + "|" + businessLine[i]);
    }

    // Sort the coupons
    Collections.sort(validCoupons, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            String[] partsA = a.split("\\|");
            String[] partsB = b.split("\\|");
            String businessA = partsA[1];
            String businessB = partsB[1];
            String codeA = partsA[0];
            String codeB = partsB[0];

            int indexA = -1, indexB = -1;
            for (int i = 0; i < businessOrder.length; i++) {
                if (businessOrder[i].equals(businessA)) {
                    indexA = i;
                }
                if (businessOrder[i].equals(businessB)) {
                    indexB = i;
                }
            }

            if (indexA != indexB) {
                return Integer.compare(indexA, indexB);
            } else {
                return codeA.compareTo(codeB);
            }
        }
    });

    // Extract the codes
    String[] result = new String[validCoupons.size()];
    for (int i = 0; i < validCoupons.size(); i++) {
        result[i] = validCoupons.get(i).split("\\|")[0];
    }

    return result;
}
