        int aIndex = getBusinessLineIndex(businessLine[getIndex(code, a)]);
        int bIndex = getBusinessLineIndex(businessLine[getIndex(code, b)]);
        if (aIndex != bIndex) {
            return Integer.compare(aIndex, bIndex);
        } else {
