    String[] businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.length; i++) {
        // Check if code is valid
        if (code[i] == null || code[i].isEmpty()) {
            continue;
        }
        boolean isValidCode = true;
        for (char c : code[i].toCharArray()) {
            if (!Character.isLetterOrDigit(c) && c != '_') {
                isValidCode = false;
                break;
            }
        }
        if (!isValidCode) {
            continue;
        }

        // Check business line
        boolean isValidBusiness = false;
        for (String business : businessOrder) {
            if (business.equals(businessLine[i])) {
                isValidBusiness = true;
                break;
            }
        }
        if (!isValidBusiness) {
            continue;
        }

        // Check isActive
        if (!isActive[i]) {
            continue;
        }

        // If all conditions are met, add to valid coupons
        validCoupons.add(code[i]);
    }

    // Sort the valid coupons
    Collections.sort(validCoupons, new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            int aIndex = -1;
            int bIndex = -1;
            for (int i = 0; i < businessOrder.length; i++) {
                if (businessLine[findIndex(code, a)].equals(businessOrder[i])) {
                    aIndex = i;
                }
                if (businessLine[findIndex(code, b)].equals(businessOrder[i])) {
                    bIndex = i;
                }
            }
            if (aIndex != bIndex) {
                return Integer.compare(aIndex, bIndex);
            } else {
                return a.compareTo(b);
            }
        }

        private int findIndex(String[] code, String s) {
            for (int i = 0; i < code.length; i++) {
                if (code[i].equals(s)) {
                    return i;
                }
            }
            return -1;
        }
    });

    return validCoupons.toArray(new String[0]);
}
